var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"......정말 괴물 같은 얼음덩어리로군.","JPN":"……本当に化け物みたいな氷塊だな。","ENG":"Wow, that is one monstrous block of ice.","TWN":"……那個冰塊就是個怪物。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L4_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"그 정도의 화염에도 완전히 녹아 내리지 않다니.","JPN":"この炎ですら完全に溶けきらないとは。","ENG":"It hasn't melted completely even with those flames.","TWN":"這火焰居然無法將它融化。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"허억...... 허억......","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呵呃……呵呃……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"괜찮아요! 아직 싸울 수 있어요!","JPN":"大丈夫！　まだまだ戦える！","ENG":"It's okay! I can still fight!","TWN":"沒關係！我還能再戰！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"헛소리! 이제 막 각성한 녀석이 무슨 소릴 하는 거냐?","JPN":"ふざけるな！　覚醒したばかりの奴が何を言ってるんだ！","ENG":"Don't be absurd! You only got your powers a few minutes ago.","TWN":"別說傻話了！妳只是個剛覺醒沒多久的小鬼而已！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"힘을 아껴라. 무리하다가 통제력을 잃으면 솔라 코덱스의 화염은 다시 네 몸에 옮겨 붙을 거다.","JPN":"力をためておけ。無理して統制力を失ったら、\\nソーラーコーデックスの炎は再びお前に燃え移るぞ。","ENG":"Save your energy. If you push yourself too hard, you'll lose control and catch fire with the flames of Solar Codex again.","TWN":"省省力氣吧。如果失去了控制力，太陽法典的火焰就會重新燒到妳身上。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아, 알겠어요!","JPN":"わ、わかった！","ENG":"O-okay!","TWN":"啊，知道了！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"......방금의 전투를 보고 확실히 알게 됐습니다.","JPN":"……さっきの戦闘を見てはっきりわかりました。","ENG":"This little skirmish has opened my eyes...","TWN":"……剛剛的戰鬥讓我明白了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"당신들을 내버려 두면 주인님께 큰 골칫거리가 되겠어요.","JPN":"あなたたちを放っておくとマスターの邪魔になるでしょう。","ENG":"You will become more than a nuisance to the Master if I let you be.","TWN":"如果讓你們繼續放肆，將會給主人帶來麻煩。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"주인님의 충실한 인형으로서...... 설사 제가 부서지더라도 당신들을 살려 두지 않겠어요.","JPN":"マスターの忠実な人形として……\\n私が壊れるとしても、あなたたちを生かしてはおけません。","ENG":"As a loyal puppet of my Master... I will not spare you, even if it breaks me in the process.","TWN":"作為主人忠實的木偶……我即使粉身碎骨也要除掉妳們。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"서, 성이 통째로 얼어붙고 있어요!","JPN":"し、城中が凍り付いてる！","ENG":"Th-the entire castle is freezing up!","TWN":"整、整個城都被凍住了！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"성뿐만이 아냐! 하늘에도 얼음이 퍼져 나가고 있어!","JPN":"城だけじゃない！　空にも氷が広がっている！","ENG":"It's not just the castle! There's ice spreading across the sky!","TWN":"不僅是城，連天上都佈滿了冰塊！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L19_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"공간 자체를 통째로 얼려 버릴 셈인가? 저건 대체 어떻게 돼먹은 녀석이야!","JPN":"空間そのものを丸ごと凍らせてしまう気なのか？　いったいどういうつもりだ？","ENG":"Is she trying to freeze the entire place? What kind of a monster is she?","TWN":"她是想把整個空間都給凍住嗎？她到底是什麼鬼啊！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"얼어붙은 세계에서, 영원히 정지하세요......","JPN":"凍り付いた世界で、永遠に停止してください……","ENG":"May you find eternal rest in this frozen world...","TWN":"冰凍的世界啊，永遠靜止下來吧……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CA_YUNA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":" 읏?","JPN":"えっ？","ENG":" Huh?","TWN":" 呃？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"힘이 빠져나간다...... 움직일 수가 없어......?","JPN":"力が抜けていく……動けない……？","ENG":"My powers are being drained from me... I can't move...","TWN":"我的力量正在流失……無法動彈了……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"주인님......? 어째서, 어째서 제게서 힘을 빼앗아 가시는 거죠......?!","JPN":"マスター……？　どうして、どうして私から力を奪うのでしょうか……？","ENG":"Master? Why are you taking my power away?","TWN":"主人……？為什麼，為什麼要奪走我的力量……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 미안해. 그 동안 방해꾼들을 막느라 애써줬는데 말이지.","JPN":"ああ、ごめんね。今まで頑張って邪魔者を止めてくれてたのに。","ENG":"Oh, sorry, sweetie. You've done a mighty fine job fending off the intruders.","TWN":"啊，抱歉，我知道妳已經盡力擋住那些人了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 조금 전에 결계를 부수고 내 최고의 인형을 되찾는 데 성공했거든.","JPN":"でも、さっき結界が破れて私の最高の人形が見つかったの。","ENG":"But I just succeeded in destroying the barrier and retrieving my greatest puppet.","TWN":"不過，我剛剛打破了結界，找到了我最棒的木偶。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그러니까 너처럼 볼품없는 인형은 이제 필요 없단 뜻이지.","JPN":"だから、あなたみたいに安っぽい人形にもう用はないの。","ENG":"So I no longer need an ugly puppet like you.","TWN":"所以，我已經不需要像妳這樣不堪的木偶了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"주, 주인님?","JPN":"マ、マスター？","ENG":"M-Master?","TWN":"主、主人？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"최초의 인형이 풀려났다고?","JPN":"最初の人形を解放しただと？","ENG":"She freed the Original Puppet?","TWN":"最初的木偶被找到了？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"마, 막아야 해! 저 녀석이 현실 세계로 나가게 되면 엄청난 재앙이 벌어질 거야!","JPN":"と、止めないと！　あいつが現実世界に出てしまったら\\nとんでもない災いが起こるはずだ。","ENG":"W-we must stop it! If the puppet gets out to the Normalside, the consequences will be cataclysmic!","TWN":"必、必須去阻止！如果讓那傢伙逃到現實社會，就會帶來更大的災難！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 고작 필멸자에 불과한 네가 이렇게 강력한 힘을 지니고 있었다는 건 좀 의외였어.","JPN":"だけど、たかが定命の者ごときのあなたが\\nこんなに強力な力を持っていたのは少し意外だったわ。","ENG":"I must admit, it was quite surprising to see how much power a mere mortal like you could wield.","TWN":"不過，妳作為區區必滅者，想不到會有這麼強大的力量，這倒是讓我很意外。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그러니 남은 힘은 내 최고의 인형, 세라펠이 기운을 차리는 데 써 줄게.","JPN":"だから私の最高の人形セラフェルが元気を取り戻すために、\\nあなたの残りの力を使ってあげるわ。","ENG":"And to honor that, I will use the remainder of your powers to give my greatest puppet, Serapel, a little extra boost.","TWN":"所以妳剩下的力量，就奉獻給我最棒的木偶，塞拉費爾吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"아아아악!!","JPN":"ああああっ！？","ENG":"Aaaah!","TWN":"啊啊啊啊！！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"후훗. 세라펠, 널 다시 보게 되다니 감회가 새롭구나.","JPN":"ふふっ。セラフェル。あなたに再会できて感慨深いわ。","ENG":"Ah, Serapel. It is truly good to see you again.","TWN":"呼呼，塞拉費爾，能再看到你，真是讓我感慨萬分。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"해방된 기념으로 뭔가 원하는 거라도 있니?","JPN":"解放された記念に何かほしいものでもある？","ENG":"Is there anything you desire to celebrate your liberation?","TWN":"作為解放的紀念，你有沒有想要的？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 저기 오랜만에 만나는 태양의 마녀가 있구나.","JPN":"ああ、久しぶりに会う太陽の魔女がいるわね。","ENG":"Ah, I see the Solar Witch over there. It's been long since I saw the last one.","TWN":"對了，那裡有好久不見的太陽魔女。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"저 녀석의 목이라도 잘라서 줄까?","JPN":"あいつの首でも切ってあげようか？","ENG":"Perhaps you'd like her head on a plate as a welcome back gift?","TWN":"我把她的人頭摘給你如何？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"레, 레일리...... 방금 온 몸에 소름이 돋았어요.","JPN":"レ、レイリー……今、とてつもない恐怖を感じたわ。","ENG":"R-Rayleigh... I just got chills all over my back.","TWN":"瑞、瑞利……我全身都起雞皮疙瘩了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"깨어나자마자 산 넘어 산이군.","JPN":"目覚めたばかりなのに、一難去ってまた一難か。","ENG":"This sure is a lot to take in after a long nap.","TWN":"我才剛覺醒不久，怎麼那麼多麻煩事啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L47_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"인형의 주인도 모자라서 최초의 인형까지 깨어나다니......","JPN":"人形の持ち主だけではなく最初の人形も目覚めてしまうとは……","ENG":"As if the Puppet Master wasn't bad enough, now the Original Puppet has awoken, too...","TWN":"一個木偶之主還不夠，現在最初的木偶也覺醒了……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"젠장, 내가 메이랑 저 녀석을 봉인한다고 죽을 고비를 몇 번이나 넘겼는데.","JPN":"くそっ、俺とメイがあいつを封印するためにあれだけ苦労したのに。","ENG":"Darn it... May and I literally almost died several times trying to lock that thing up.","TWN":"可惡，以前我和梅伊為了封印那個傢伙差點就死翹翹了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"그래도 한 번 이긴 상대란 뜻이잖아요! 이번에도 할 수 있을 거예요!","JPN":"でも、一度勝った相手ってことだよね！　今回も勝てるはずだよ！","ENG":"But that means you beat her at least once before! I'm sure we can do it again!","TWN":"但至少你贏過它啊！這次一定也可以的！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"바보 같은 소리로군. 지금의 네겐 승산이 전혀 없다, 유나.","JPN":"バカなことを言うな。今のお前にはまったく勝ち目がない。","ENG":"Don't be stupid. You don't have a chance in your current state, Yuna.","TWN":"你在說什麼蠢話，現在妳沒有任何勝算，尤娜。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"저 녀석이 공격해 오면 아무것도 생각하지 말고 전력으로 도망쳐.","JPN":"あいつが攻撃してきたら何も考えずに全力で逃げろ。","ENG":"If that thing starts attacking, just run away as fast as you can without thinking about anything else.","TWN":"如果它攻擊過來，就什麼都不要想，只管全力跑。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"네......? 그럼 레일리는?","JPN":"え……？　じゃ、レイリーは？","ENG":"Huh? Then what about you?","TWN":"什麼……？那瑞利你呢？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"네가 도망갈 시간을 벌어 봐야지..","JPN":"お前が逃げる時間を稼がないと……","ENG":"I'll try my best to buy you enough time to get away.","TWN":"我來爭取妳逃跑的時間…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"하지만!","JPN":"でも！","ENG":"But!","TWN":"可是！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"네 할머니의 부탁도 있어서 어리광을 받아 줬지만 이건 경우가 달라!","JPN":"お前の婆さんの頼みではあったが、今はそんな場合じゃない！","ENG":"Listen, fledgling. I gave you what you wanted for your grandmother's sake, but this is an entirely different story!","TWN":"剛剛是因為妳奶奶拜託我，所以我才會縱容妳，但這次不一樣！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"애초에 저 둘 상대로는 시간을 벌 수 있을지도 확신이 없어. 알겠냐.","JPN":"あの二人を相手に時間を稼げるかどうかもわからないんだ。わかったか？","ENG":"I'm not even sure if I can buy much time against those two. Get my drift?","TWN":"面對他們兩個，我都不知道到底能不能爭取到時間，知道嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"주인님......","JPN":"マスター……","ENG":"Master...","TWN":"主人……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래, 나의 세라펠. 뭘 원하는지 말만 하렴.","JPN":"ああ、私のセラフェル。ほしいものを言ってみなさい。","ENG":"Yes, my Serapel. Tell me what you desire.","TWN":"嗯，塞拉費爾，儘管說出你的願望。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"저는...... 너무 오랫동안 고통에 굶주려 있었어요.","JPN":"私は……とても長く苦しみに飢えていました。","ENG":"I've been so hungry for suffering for so long.","TWN":"我……一直以來渴望痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"살을 에는 채찍의 고통도, 바늘에 꿰뚫리는 학대의 고통도......","JPN":"身を切るようなムチの苦しみも、針が突き刺さる虐待の苦しみも……","ENG":"The pain of the whip lashing against the skin... The agony of needles piercing through my body in glorious abuse...","TWN":"我已經很久沒有感受到鞭子割肉的痛苦，針紮皮膚的痛苦……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"두 눈을 태우는 태양의 열기를 느낀 지도...... 너무나 오래되었습니다.","JPN":"両目を焼く太陽の熱を感じたのも……あまりにも昔のことです。","ENG":"The scorching sensation of the sun's rays smoldering my eyes out... It's all been too long.","TWN":"也很久沒有感受到…能夠灼燒雙眼的太陽火焰了… 。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그러니 저들이, 제게 고통을 주는 것을 허락하소서.","JPN":"だから、彼らが私に苦しみを与えることをお許しください。","ENG":"So please allow them to grant me suffering.","TWN":"所以請您允許他們給我痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 그렇구나. 그게 네가 원하는 거였구나.","JPN":"ああ、そうか。それがあなたの望みだったのね。","ENG":"Ah, I see. So that's what you desire.","TWN":"啊，原來如此，這就是你想要的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"좋아. 네가 원한다면 그렇게 해야겠지.","JPN":"いいわ。あなたが望むならそうしてあげる。","ENG":"Very well. If that's what you want, you shall have it.","TWN":"好，如你所願。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"저 하찮은 인형에게 남은 힘을 모두 뽑아내는 대로 네게 충분한 고통을 안겨 줄게.","JPN":"あのつまらない人形から残りの力を全部吸い上げ次第、\\nあなたに十分な苦しみを味わわせてあげるわ。","ENG":"As soon as I drain the rest of the power from that pathetic puppet, I will grant you the suffering you desire.","TWN":"等我把那個不堪的木偶的力量全部抽出來後，就賜予你足夠的痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"응......?","JPN":"ん……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_03"},{"id":"L26_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아아아악!!","JPN":"あああああっ！？","ENG":"Aaaah!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_11"},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>감히! 감히 나의 레지나 님을 모욕하다니이이이이!</color>","JPN":"<color=#ff3636>おのれ！　よくも我々のレジーナ様を侮辱したなぁぁぁ！</color>","ENG":"<color=#ff3636>How dare you! How dare you insult my Reginaaaa!</color>","TWN":"<color=#ff3636>放肆！竟敢汙辱我的蕾佳娜小姐！！</color>"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>더러운 인형술사 년......! 용서치 않겠다!</color>","JPN":"<color=#ff3636>汚らわしい人形術者ごときが……！　許さない！</color>","ENG":"<color=#ff3636>You filthy puppeteer! I shall make you pay for this!</color>","TWN":"<color=#ff3636>可惡的木偶師……！我饒不了你！</color>"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"저, 저 괴물은 또 뭐야?","JPN":"あ、あの化け物は何なの？","ENG":"W-where the heck did that monster come from?","TWN":"那、那又是什麼怪物！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"모, 못 보겠어......! 머리가 아파서......!","JPN":"み、見てられない……！　頭が痛くて……！","ENG":"I-I can barely look at it... It's giving me a headache!","TWN":"我、我看不下去了……！我的頭好痛……！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"말도 안 돼...... 공간을 뚫고 이면세계에 나타나다니......","JPN":"あり得ない……空間を割って​裏世界に現れるだと……","ENG":"Impossible... It tore through the fabric of spacetime to appear in the Counterside...","TWN":"不可能……怎麼可能突破空間出現在異界……"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"최초의 인형과...... 대등한 종류의 힘?","JPN":"最初の人形と……対等な種類の力？","ENG":"A power that equals that of the Original Puppet?","TWN":"和最初的木偶……有著相同的力量？"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"젠장, 오늘 무슨 날이냐!","JPN":"くそっ、最悪のタイミングだ！","ENG":"Darn it! It's a dumpster fire today, huh?","TWN":"可惡，今天到底是什麼日子啊！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L34_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"유나! 불꽃으로 동료들을 감싸라! 저 괴물의 촉수에 닿으면 끝장이야!","JPN":"ユナ！　炎で仲間たちをかばえ！　あの怪物の触手に当たったらおしまいだ！","ENG":"Yuna! Shield your colleagues with your flames! They'll be done for if that monster's tentacles touch them!","TWN":"尤娜！快用火焰包圍住同伴！被那個怪物的觸角碰到就糟了！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아, 알겠어요!","JPN":"わ、わかった！","ENG":"G-got it!","TWN":"啊，知道了！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"큭...... 후우...... 후후훗......","JPN":"くっ……ふぅ……ふふふっ……","ENG":"Ngh... Phew... Hah hah hah...","TWN":"咳……呼……呼呼……"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"저 인형이...... 네가 점찍어 둔 장난감이었나, 탐식자?","JPN":"あの人形が……あなたが目をつけておいたおもちゃだったのね、貪食者？","ENG":"So... Have you already laid claim to that puppet as your toy, Devourer?","TWN":"那個木偶……原來是你看中的玩具啊，貪食者？"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"본의 아니게 내가 가지고 놀아 버렸네. 사과라도 해야 할까?","JPN":"心ならずも私が弄んでしまったわ。謝ったほうがいいかしら？","ENG":"Looks like I ended up playing with her instead without realization. Do I owe you an apology?","TWN":"我沒想過要玩弄她，要不我道個歉？"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>닥쳐라! 천박한 년! 나의 소중한 레지나 님을 또다시 모욕하다니!</color>","JPN":"<color=#ff3636>黙れ！　下品なあばずれが！　\\n我々の大切なレジーナ様をまた侮辱するとは！</color>","ENG":"<color=#ff3636>Silence, you vulgar cur! How dare you insult my precious Regina again!</color>","TWN":"<color=#ff3636>閉嘴！沒用的傢伙！你敢侮辱我尊貴的蕾佳娜小姐！</color>"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>너 따위는 성찬에 올릴 가치조차 없다! 이 자리에서 잿더미가 되어 사라져라!</color>","JPN":"<color=#ff3636>貴様なぞ聖餐に供える価値すらない！　この場で灰になって消えろ！</color>","ENG":"<color=#ff3636>You are not even worthy of a feast! Just turn to ashes and be no more!</color>","TWN":"<color=#ff3636>你連作為我的配菜都還不如啊！給我化成灰燼，消失吧！</color>"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"끄아아아아아아악!!","JPN":"ぐあああぁぁぁ！？","ENG":"Arrrrrgh!","TWN":"啊啊啊啊啊啊啊啊！！"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_14"},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에블린...... 보고 있어?","JPN":"エヴリン……見てるか？","ENG":"Evelyn... Are you seeing this?","TWN":"伊芙琳……你看到了嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. 인형의 주인이...... 소멸됐어.","JPN":"うん。人形の持ち主が……消滅した。","ENG":"Yeah. The Puppet Master was just got... disintegrated.","TWN":"嗯，木偶之主……居然被消滅了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"일이 이렇게 될 줄은 상상도 못했는데......","JPN":"こんなことになるとは思ってもみなかったわ……","ENG":"I never imagined things would end up like this...","TWN":"沒想到事情會發展成這個樣子……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아아, 레지나 님......","JPN":"ああ、レジーナ様……","ENG":"Oh... Miss Regina...","TWN":"啊，蕾佳娜小姐……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"가여우신 분. 이제 걱정하실 것 없어요. 제가 이렇게 왔으니까요.","JPN":"かわいそうなお方。もう心配することはありませんよ。こうして我々が参りましたから。","ENG":"You poor thing. Don't you worry now. I'm here.","TWN":"真是可憐，您不用擔心，我來了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"으윽...... 으으윽......","JPN":"うう……ううっ……","ENG":"Ngh... Hngh...","TWN":"唔……唔唔……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"조금만 쉬고 계세요. 맥크레디의 영지까지 금방 모셔다 드릴 테니까요.","JPN":"少し休んでいてください。マクレディーの領地まですぐお送りします。","ENG":"Take a little nap. I'll have you taken to the MacCready Estate in no time.","TWN":"妳稍微休息一下，我馬上把妳送到麥克蕾蒂的領地。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"또 망가져 버렸나......?","JPN":"また、壊れてしまった……？","ENG":"Has another one been broken again?","TWN":"又壞了嗎……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"풀려나자마자 새로운 주인을 만들어야 하다니...... 귀찮은 일이로군.","JPN":"解放されてすぐ新しいマスターを作らなきゃいけないなんて……面倒になったわ。","ENG":"Alas, I must build a new master just as I've been liberated... What a hassle.","TWN":"剛出來就要找新的主人……真是麻煩。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"......새로운 주인을 만든다고? 무슨 소리야?","JPN":"……新しいマスターを作る？　どういうこと？","ENG":"Build a new master? What are you talking about?","TWN":"……找新的主人？那是什麼意思？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"넌 인형이라면서? 주인이 널 만든 거 아니었어?","JPN":"あなたはお人形でしょう？　マスターがあなたを作ったんじゃないの？","ENG":"I thought you're a puppet. Didn't your master build you?","TWN":"你不是木偶嗎？不是你的主人製造你的嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"주인은 인형을 지배할 뿐, 만드는 자가 아니다.","JPN":"マスターは人形を支配するだけで、作る者ではない。","ENG":"The masters only rule over the puppet; they are not the creators.","TWN":"主人只能控制木偶，並不能製造。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"당연한 이야기지.","JPN":"当然な話よ。","ENG":"It's too obvious to mention.","TWN":"這還要問。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"그, 그래......?","JPN":"そ、そうなの……？","ENG":"Oh... I-it is?","TWN":"是、是嗎……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"하지만 주인이 사라졌으면 자유로워진 거잖아. 왜 새로운 주인을 찾는 거야?","JPN":"けど、マスターがいなくなったから自由になれたんじゃない？　なんで新しいマスターを探すの？","ENG":"But if the master's gone, you're free now. Why would you want to find a new master?","TWN":"但如果主人消失了不就自由了嗎？為什麼還要找新的主人？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"......너는 날 전혀 이해하지 못하고 있군.","JPN":"……あなたは私を理解していないようね。","ENG":"You do not comprehend me at all.","TWN":"……看來妳根本不懂我。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"인형술사가 가지고 놀 인형을 원하듯이, 인형은 자기를 움직여 줄 주인을 원하기 마련이다.","JPN":"人形術者が操り人形を欲しがるように、人形も自分を操ってくれるマスターを欲しがるものよ。","ENG":"Just as a puppeteer wants a puppet to control, the puppet desires a puppeteer to bring them motion.","TWN":"就像木偶師挑選心儀的木偶一樣，木偶也想要可以操控自己的主人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래서 나는 나의 주인을 만들었지.","JPN":"だから私は私のマスターを作ったの。","ENG":"That is why I created my own master.","TWN":"所以我親自挑選了我的主人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"주의 깊고 세심하게 조립한 인형에...... 주인이라는 역할을 부여해서.","JPN":"丁寧に組み立てた人形に……マスターという役割を付与して。","ENG":"I've carefully and delicately assembled a puppet... and assigned it the role of master.","TWN":"我給謹慎且仔細組裝起來的木偶……賦予了主人的角色。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"나를 학대하고 괴롭히고, 고통의 희열을 줄 주인을.","JPN":"私を虐待して苦しめ、苦しみの喜びを与えてくれるマスターを。","ENG":"A master to torture me, agonize me, and bring me the ecstasy of suffering.","TWN":"一個可以虐待折磨我，給我痛苦之喜悅的主人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"무, 무슨 말을 하는 거야? 하나도 모르겠어.","JPN":"な、何を言ってるの？　わけがわからない……","ENG":"W-what are you talking about? I don't understand anything you're saying.","TWN":"你、你在說什麼呢？我一點也聽不懂。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"......보아하니 네가 새로운 태양의 대마녀인 것 같군. 그런가?","JPN":"……見たところ、あなたが新しい太陽の大魔女のようね。そうでしょう？","ENG":"It appears that you are the new Great Witch of the Sun. Are you?","TWN":"……看來妳是新的太陽大魔女，是嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"견습이다. 견습 대마녀.","JPN":"見習いだ。見習いの大魔女。","ENG":"In training. Great witch in training.","TWN":"是見習，見習大魔女。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L32_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そう。","ENG":"I see...","TWN":"原來如此。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"나는 나를 만족시킬 만한 고통을 찾기 위해 오랜 시간을 방황해 왔다.","JPN":"私は自分を満たせそうな苦しみを探すために長い間彷徨ってきた。","ENG":"I've wandered for a very long time in search of someone to grant me suffering that would satisfy me.","TWN":"長久以來，我不斷彷徨，一直在尋找可以滿足我的痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"네 선대의 대마녀는 그런 나를 만족시켜줄 만한 자였지.","JPN":"あなたの先代の大魔女はそんな私を満足させるに値する者だった。","ENG":"Your predecessor was one of those who was capable of bringing me such satisfaction.","TWN":"妳的先祖大魔女，剛好是可以滿足我的人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그녀가 뿜어내는 화염은 지독히도 뜨겁고, 황홀하게 고통스러웠으니까.","JPN":"彼女が放つ炎はとても熱くて、うっとりするくらい辛かったから。","ENG":"Her flames were scornfully hot, and ecstatically painful.","TWN":"她的火焰極其炙熱，讓我著迷並痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 넌 아직 너무 부족해.","JPN":"でも、あなたはまだまだ足りなさすぎる。","ENG":"But you are not enough yet.","TWN":"不過，妳現在還不夠。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래서야 내가 만족할 만한 고통을 줄 수 있을 것 같지 않군.","JPN":"その程度では私が満足できる苦しみを与えることはできないわ。","ENG":"You won't be able to grant me the amount of suffering that I would find satisfactory.","TWN":"妳根本就給不了我想要的痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그러니 지금은 널 살려 두겠다.","JPN":"だから今はあなたを生かしておく。","ENG":"So for now, I shall let you live.","TWN":"所以，我今天就饒妳一命。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"다음에 만날 때는 부디 너의 화염으로 나에게 희열을 줄 수 있기를 기대하지.","JPN":"次に会う時はあなたの炎が私を喜ばせてくれることを期待するわ。","ENG":"I hope you will be able to grant me a greater thrill with your flames the next time we meet.","TWN":"等日後再相見，我希望妳的火焰能給我帶來喜悅。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"걱정 마라, 세라펠.","JPN":"心配はいらない、セラフェル。","ENG":"Don't worry, Serapel.","TWN":"放心吧，塞拉費爾。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_LIST_SELECT"},{"id":"L44_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"다음에는 널 완전히 잿더미로 만들 만큼 뜨거운 화염을 준비해 둘 테니까.","JPN":"今度はお前を完全に灰にするほどの熱々の炎を用意しておくからな。","ENG":"We'll be sure to prepare a flame so hot that it'll turn you into a pile of ashes next time.","TWN":"下次我一定會準備能把你燒成灰燼的炙熱火焰。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아...... 그래, 너무나 기대되는걸.","JPN":"ええ……わかったわ。とても楽しみね。","ENG":"Ah, yes... I do look forward to that immensely...","TWN":"啊……是嗎，我很期待。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그 말, 꼭 지켜 주길 바라겠다.","JPN":"今の話、絶対に守ってほしいわ。","ENG":"I hope you keep your word.","TWN":"請你務必，遵守你的約定。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};